// // This module implements a 3-bit synchronous binary counter with an enable signal.
// The counter decrements its value on each clock cycle when the enable signal is active.
// There is also an active-high reset signal.
module sync_counter(
    input wire clk,
    input wire rst_n,
    input wire enable,
    output reg [2:0] count
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count <= 3'b000;
    end else if (enable) begin
        count <= count + 1;
    end
end

endmodule

